@Test public void skipsDisabledSelectElement() {
    String html = "<form><select name='choice' disabled><option value='one'>One</option><option value='two' selected>Two</option></select></form>";
    Document doc = Jsoup.parse(html);
    FormElement form = (FormElement) doc.select("form").first();
    List<Connection.KeyVal> data = form.formData();
    assertEquals(0, data.size());
}

@Test public void skipsDisabledRadioButton() {
    String html = "<form><input type='radio' name='option' value='yes' checked disabled><input type='radio' name='option' value='no'></form>";
    Document doc = Jsoup.parse(html);
    FormElement form = (FormElement) doc.select("form").first();
    List<Connection.KeyVal> data = form.formData();
    assertEquals(0, data.size());
}

@Test public void includesEnabledTextareaWithDisabledInput() {
    String html = "<form><textarea name='comment'>Hello</textarea><input name='disabled_field' value='value' disabled></form>";
    Document doc = Jsoup.parse(html);
    FormElement form = (FormElement) doc.select("form").first();
    List<Connection.KeyVal> data = form.formData();
    assertEquals(1, data.size());
    assertEquals("comment=Hello", data.get(0).toString());
}
